  ('medical-tech-moex-17414', 'medical-tech', 'medical-tech-moex-097-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關骨髓化生不良症候群（myelodysplastic syndrome）之分類，新的WHO與舊的FAB（French- American-British）系統有些不同。下列何種myelodysplastic syndrome不曾出現於FAB系統，但新的 WHO系統已經將其列入myelodysplastic syndrome之中？', '["Refractory cytopenia with multilineage dysplasia（RCMD）", "Chronic myelomonocytic leukemia（CMML）", "Refractory anemia with ringed sideroblasts（RARS）", "Refractory anemia（RA）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:07+00:00", "source_pdf_sha1": "379e398c1697", "answer_pdf_sha1": "fda5b62c7319", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "108", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 75, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
